# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import secrets
import json
from functools import wraps
from urllib.parse import urlencode
import requests
from flask import Flask, redirect, request, session, url_for, jsonify
from jose import jwt, JWTError

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'issuer': os.environ.get('OIDC_ISSUER', 'https://your-oidc-provider.com'),
    'authorization_endpoint': os.environ.get('OIDC_AUTH_ENDPOINT', 'https://your-oidc-provider.com/authorize'),
    'token_endpoint': os.environ.get('OIDC_TOKEN_ENDPOINT', 'https://your-oidc-provider.com/token'),
    'userinfo_endpoint': os.environ.get('OIDC_USERINFO_ENDPOINT', 'https://your-oidc-provider.com/userinfo'),
    'jwks_uri': os.environ.get('OIDC_JWKS_URI', 'https://your-oidc-provider.com/.well-known/jwks.json'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid profile email'
}

jwks_cache = None


def get_jwks():
    global jwks_cache
    if jwks_cache is None:
        response = requests.get(OIDC_CONFIG['jwks_uri'])
        jwks_cache = response.json()
    return jwks_cache


def verify_and_decode_token(token):
    try:
        unverified_header = jwt.get_unverified_header(token)
        jwks = get_jwks()
        
        rsa_key = {}
        for key in jwks['keys']:
            if key['kid'] == unverified_header['kid']:
                rsa_key = {
                    'kty': key['kty'],
                    'kid': key['kid'],
                    'use': key['use'],
                    'n': key['n'],
                    'e': key['e']
                }
                break
        
        if not rsa_key:
            raise ValueError('Unable to find appropriate key')
        
        payload = jwt.decode(
            token,
            rsa_key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer']
        )
        
        return payload
    except JWTError as e:
        raise ValueError(f'Token verification failed: {str(e)}')


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def index():
    if 'user' in session:
        return f'''
        <h1>Welcome, {session['user'].get('name', 'User')}!</h1>
        <p>Email: {session['user'].get('email', 'N/A')}</p>
        <p>Subject: {session['user'].get('sub', 'N/A')}</p>
        <a href="/profile">View Profile</a><br>
        <a href="/logout">Logout</a>
        '''
    return '<h1>Home Page</h1><a href="/login">Login</a>'


@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce
    }
    
    authorization_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f'Error: {error} - {request.args.get("error_description", "")}', 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return 'Authorization code not found', 400
    
    if state != session.get('oauth_state'):
        return 'Invalid state parameter', 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret']
    }
    
    token_response = requests.post(
        OIDC_CONFIG['token_endpoint'],
        data=token_data,
        headers={'Content-Type': 'application/x-www-form-urlencoded'}
    )
    
    if token_response.status_code != 200:
        return f'Token exchange failed: {token_response.text}', 400
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if not id_token:
        return 'ID token not found in response', 400
    
    try:
        claims = verify_and_decode_token(id_token)
    except ValueError as e:
        return f'Token verification failed: {str(e)}', 400
    
    if claims.get('nonce') != session.get('oauth_nonce'):
        return 'Invalid nonce', 400
    
    user_info = {
        'sub': claims.get('sub'),
        'name': claims.get('name'),
        'email': claims.get('email'),
        'preferred_username': claims.get('preferred_username'),
        'email_verified': claims.get('email_verified'),
        'picture': claims.get('picture')
    }
    
    session['user'] = user_info
    session['access_token'] = access_token
    if refresh_token:
        session['refresh_token'] = refresh_token
    
    session.pop('oauth_state', None)
    session.pop('oauth_nonce', None)
    
    return redirect(url_for('index'))


@app.route('/profile')
@login_required
def profile():
    return jsonify(session['user'])


@app.route('/userinfo')
@login_required
def userinfo():
    access_token = session.get('access_token')
    if not access_token:
        return 'Access token not found', 400
    
    headers = {'Authorization': f'Bearer {access_token}'}
    response = requests.get(OIDC_CONFIG['userinfo_endpoint'], headers=headers)
    
    if response.status_code != 200:
        return f'Failed to fetch user info: {response.text}', 400
    
    return jsonify(response.json())


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))


if __name__ == '__main__':
    app.run(debug=True, port=5000)